import React, { useState } from 'react';

const language = ['C++.png'];
const proficiency = [5];
const LanguageList = () => {
    const languageList = language.map((item)=>{
        return <img src={require(`../resources/${item}`)} alt="CPlus"/>
    });
    const proficiencyLevel = proficiency.map((item)=>{
        return <div className="cell"><i className="check icon"></i></div>;
    });
    return (<div className="grid assessmentContent">
        <div className="cell">
            <div className="ui small image" style={{borderRadius:"50%",padding: "0em", maxHeight:"2rem",maxWidth:"2rem",zIndex:"5"}}>
                { languageList }
            </div>
        </div>
        <div className="cell"><i className="check icon"></i></div>
        <div className="cell"><i className="check icon"></i></div>
        <div className="cell"><i className="check icon"></i></div>
        <div className="cell"><i className="check icon"></i></div>
        <div className="cell"><i className="check icon"></i></div>
    </div>);
};

export default LanguageList;
